// This handler demonstrates OPA-based document filtering
// In production, the OPA policy would be evaluated via the OPA client

const auth = msg.req.auth || {};
const query = msg.req.query || {};

// Mock document database with various classifications and owners
const allDocuments = [
    { id: 'doc-1', title: 'Public Report Q1', classification: 'public', department: 'sales', owner: 'user-1' },
    { id: 'doc-2', title: 'Internal Memo', classification: 'internal', department: 'hr', owner: 'user-2' },
    { id: 'doc-3', title: 'Confidential Budget', classification: 'confidential', department: 'finance', owner: 'user-3' },
    { id: 'doc-4', title: 'Project Plan', classification: 'internal', department: 'engineering', owner: auth.sub },
    { id: 'doc-5', title: 'Restricted Personnel File', classification: 'restricted', department: 'hr', owner: 'user-2' },
    { id: 'doc-6', title: 'My Personal Notes', classification: 'internal', department: 'engineering', owner: auth.sub }
];

// Simulate OPA policy evaluation
// In production, this would call the OPA server
function evaluateOpaPolicy(document, user) {
    // Admin can see everything
    if (user.roles && user.roles.includes('admin')) {
        return true;
    }

    // Users can see their own documents
    if (document.owner === user.sub) {
        return true;
    }

    // Users can see public documents
    if (document.classification === 'public') {
        return true;
    }

    // Managers can see internal documents in their department
    if (user.roles && user.roles.includes('manager')) {
        if (document.classification === 'internal' && 
            document.department === user.department) {
            return true;
        }
    }

    // Department heads can see confidential in their department
    if (user.roles && user.roles.includes('department_head')) {
        if (['internal', 'confidential'].includes(document.classification) &&
            document.department === user.department) {
            return true;
        }
    }

    return false;
}

// Build user context for policy evaluation
const userContext = {
    sub: auth.sub || 'anonymous',
    roles: auth.roles || [],
    department: auth.payload?.department || 'unknown'
};

// Filter documents based on OPA policy
const accessibleDocuments = allDocuments.filter(doc => 
    evaluateOpaPolicy(doc, userContext)
);

// Apply any query filters
let filteredDocuments = accessibleDocuments;

if (query.department) {
    filteredDocuments = filteredDocuments.filter(d => d.department === query.department);
}

if (query.classification) {
    filteredDocuments = filteredDocuments.filter(d => d.classification === query.classification);
}

const limit = parseInt(query.limit) || 20;
filteredDocuments = filteredDocuments.slice(0, limit);

msg.res.json({
    documents: filteredDocuments,
    total: accessibleDocuments.length,
    filteredByPolicy: true,
    userContext: {
        sub: userContext.sub,
        roles: userContext.roles,
        department: userContext.department
    }
});

return null;

// This handler demonstrates OPA-based access control for a specific resource

const auth = msg.req.auth || {};
const documentId = msg.req.params.id;

// Mock document database
const documents = {
    'doc-1': {
        id: 'doc-1',
        title: 'Public Report Q1',
        content: 'This is a public quarterly report...',
        classification: 'public',
        department: 'sales',
        owner: 'user-1',
        metadata: { createdAt: '2024-01-15', version: 1 }
    },
    'doc-2': {
        id: 'doc-2',
        title: 'Internal Memo',
        content: 'Internal HR communication...',
        classification: 'internal',
        department: 'hr',
        owner: 'user-2',
        metadata: { createdAt: '2024-02-20', version: 2 }
    },
    'doc-3': {
        id: 'doc-3',
        title: 'Confidential Budget',
        content: 'Budget allocations for next fiscal year...',
        classification: 'confidential',
        department: 'finance',
        owner: 'user-3',
        metadata: { createdAt: '2024-03-10', version: 1 }
    }
};

const document = documents[documentId];

if (!document) {
    msg.res.status(404).json({
        type: 'https://api.example.com/errors/not-found',
        title: 'Document Not Found',
        status: 404,
        detail: `Document with ID '${documentId}' was not found`
    });
    return null;
}

// Build OPA input for policy evaluation
const opaInput = {
    method: 'GET',
    path: ['documents', documentId],
    user: {
        sub: auth.sub || 'anonymous',
        roles: auth.roles || [],
        department: auth.payload?.department || 'unknown'
    },
    resource: {
        id: document.id,
        owner: document.owner,
        classification: document.classification,
        department: document.department
    }
};

// Simulate OPA policy decision
// In production, this would call: POST http://localhost:8181/v1/data/api/authz/allow
function evaluatePolicy(input) {
    const { user, resource } = input;

    // Admin has full access
    if (user.roles.includes('admin')) {
        return { allow: true, reason: 'admin_access' };
    }

    // Owner has full access to their documents
    if (resource.owner === user.sub) {
        return { allow: true, reason: 'owner_access' };
    }

    // Public documents are accessible to all authenticated users
    if (resource.classification === 'public') {
        return { allow: true, reason: 'public_document' };
    }

    // Managers can access internal docs in their department
    if (user.roles.includes('manager') &&
        resource.classification === 'internal' &&
        resource.department === user.department) {
        return { allow: true, reason: 'manager_department_access' };
    }

    // Department heads have broader access
    if (user.roles.includes('department_head') &&
        ['internal', 'confidential'].includes(resource.classification) &&
        resource.department === user.department) {
        return { allow: true, reason: 'department_head_access' };
    }

    return {
        allow: false,
        reason: 'insufficient_permissions',
        requiredConditions: [
            'Be the document owner',
            'Have admin role',
            'Have manager role for department internal docs',
            'Have department_head role for confidential docs'
        ]
    };
}

const policyDecision = evaluatePolicy(opaInput);

if (!policyDecision.allow) {
    msg.res.status(403).json({
        type: 'https://api.example.com/errors/forbidden',
        title: 'Access Denied by Policy',
        status: 403,
        detail: 'You do not have permission to access this document',
        policyDecision: {
            allowed: false,
            reason: policyDecision.reason,
            requiredConditions: policyDecision.requiredConditions,
            resourceClassification: document.classification,
            resourceDepartment: document.department
        }
    });
    return null;
}

// Access granted - return document
msg.res.json({
    ...document,
    _policyDecision: {
        allowed: true,
        reason: policyDecision.reason
    }
});

return null;

// Creating a document - OPA can enforce classification rules

const auth = msg.req.auth || {};
const body = msg.req.body;

// Simulate OPA policy check for document creation
// Policy might enforce:
// - Users can only create documents up to their clearance level
// - Users can only create documents in their department
// - Restricted classification requires special approval

const userClearanceLevel = {
    'user': ['public', 'internal'],
    'manager': ['public', 'internal', 'confidential'],
    'admin': ['public', 'internal', 'confidential', 'restricted']
};

const highestRole = auth.roles?.includes('admin') ? 'admin' :
                    auth.roles?.includes('manager') ? 'manager' : 'user';

const allowedClassifications = userClearanceLevel[highestRole];
const requestedClassification = body.classification || 'internal';

if (!allowedClassifications.includes(requestedClassification)) {
    msg.res.status(403).json({
        type: 'https://api.example.com/errors/forbidden',
        title: 'Classification Not Allowed',
        status: 403,
        detail: `You are not authorized to create documents with '${requestedClassification}' classification`,
        policyDecision: {
            allowed: false,
            reason: 'insufficient_clearance',
            userClearance: highestRole,
            allowedClassifications: allowedClassifications,
            requestedClassification: requestedClassification
        }
    });
    return null;
}

// Create the document
const newDocument = {
    id: 'doc-' + Math.random().toString(36).substr(2, 9),
    title: body.title,
    content: body.content,
    classification: requestedClassification,
    department: body.department || auth.payload?.department || 'general',
    owner: auth.sub,
    createdAt: new Date().toISOString(),
    metadata: {
        version: 1,
        createdBy: auth.preferredUsername || auth.sub
    }
};

msg.res.status(201).json(newDocument);

return null;

// Delete requires admin role (enforced by endpoint scope)
// OPA could add additional checks like:
// - Can't delete documents with active references
// - Audit logging requirements
// - Retention policy compliance

const documentId = msg.req.params.id;

// Mock: check if document exists
const existingDocIds = ['doc-1', 'doc-2', 'doc-3'];

if (!existingDocIds.includes(documentId)) {
    msg.res.status(404).json({
        type: 'https://api.example.com/errors/not-found',
        title: 'Document Not Found',
        status: 404,
        detail: `Document with ID '${documentId}' was not found`
    });
    return null;
}

// In production, this would:
// 1. Check OPA for additional deletion policies
// 2. Soft delete or archive the document
// 3. Log the deletion for audit
// 4. Notify relevant stakeholders

const auth = msg.req.auth || {};
node.log(`Document ${documentId} deleted by admin ${auth.sub}`);

msg.res.status(204).end();

return null;
